var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"조금 늦었으나, 구원기사단의 고유무장에 관한 인계 절차는 무사히 끝마쳤습니다.","JPN":"少し遅くなりましたが、救世騎士団の固有武装については無事引き渡しが終わりました。","ENG":"The handover process for the Knights of Redemption's Unique Gear is complete. A bit late, but everything went smoothly.","TWN":"雖然有些晚了，但關於救贖騎士團的專屬武裝的交接程式已經順利完成。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"더 이상 이쪽을 신경 쓰실 필요는 없을 것 같군요.","JPN":"もうこちらを気にする必要はなさそうですね。","ENG":"You won't need to worry about things on this end anymore.","TWN":"我想你不必再操心這邊的事情了。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 설마 이런 식으로 일을 진행했을 줄은 몰랐어요.","JPN":"申し訳ありません。まさかこういう風になるとは思わなかったもので。","ENG":"I'm sorry. I had no idea things would be handled this way.","TWN":"對不起，我沒想到事情會以這種方式進行。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"로터스 관리국 쪽에서 흔쾌히 허락해줬다고 들었는데… 설마 주먹구구식이었을 줄은.","JPN":"ロータス管理局が快諾してくれたと聞きましたが……まさかこれほど大ざっぱだったとは。","ENG":"I heard the Lotus Administration approved it without hesitation... but I didn't think it would be so sloppy.","TWN":"聽說洛德斯管理局那邊爽快地答應了……沒想到竟然是草率行事。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"다른 시니어 분들도 동의한 내용이니 상관없습니다.","JPN":"他のシニアも同意された内容ですので、構いません。","ENG":"It's fine. The other Seniors agreed as well.","TWN":"其他Senior也同意，所以沒關係。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"비록 연구욕이 불타오른다며 환희에 찬 시니어님의 의지가 다시금 꺾여버렸으나, 사소한 문제죠.","JPN":"研究意欲に火が付いたと大喜びしていたシニアの意志が、またへし折れてしまいましたが、些細なことです。","ENG":"Though one of them, who was practically vibrating with excitement, had his hopes dashed again. Still, a minor issue.","TWN":"雖然研究欲望燃燒起來，充滿歡喜的Senior的意志再次被打擊，但這只是小問題。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……거듭 죄송합니다.","JPN":"……本当に申し訳ありません。","ENG":"...Once again, my apologies.","TWN":"……再次非常抱歉。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아닙니다. 오히려 시국으로 인해 큰 도움을 드릴 수 없어 부끄러울 따름이군요.","JPN":"いいえ。むしろこちらの状況であまり助けになれないのがお恥ずかしいかぎりです。","ENG":"No need. If anything, I'm ashamed we couldn't be of more help given the situation.","TWN":"不是的。反而因為時局無法給予太多幫助，感到有些慚愧。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"부디, 건투를 빌겠습니다.","JPN":"ご健闘を祈ります。","ENG":"I wish you good luck.","TWN":"祝你好運，希望你能成功。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽은 아직 별다른 움직임이 없습니다. 다른 쪽은 어떤가요?","JPN":"こちらはまだ特に動きは見えません。そちらはいかがですか？","ENG":"Nothing to report on this end yet. What about your side?","TWN":"這邊暫時沒有什麼動靜。另一邊怎麼樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽도 문제없습니다.","JPN":"こちらも問題ありません。","ENG":"All clear here as well.","TWN":"我們這邊也沒問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"외부 구역에도 감시 장비를 대동했으니, 무슨 일이 있어도 즉각적으로 대응 가능해요.","JPN":"外部区域にも監視装備を持って行きましたから、何があってもただちに対応可能です。","ENG":"We've got surveillance equipment covering the outer perimeter. We'll respond immediately if anything happens.","TWN":"外部區域也配備了監控設備，所以無論發生什麼事情都能立即應對。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부. 마찬가지로 이상 없습니다.","JPN":"本部。同じく異常なしです。","ENG":"This is HQ. No abnormalities here either.","TWN":"總部，一樣沒有異常。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"혹시라도 적의 움직임이 포착되면 연락 드리겠습니다.","JPN":"敵の動きを捉えたらご連絡いたします。","ENG":"I'll contact you if we detect any enemy movement.","TWN":"如果發現敵人的動向，我會聯絡你。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"하아암…….","JPN":"ふああー……","ENG":"*Yawn...*","TWN":"哈啊啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 집중해주세요. 언제 레드시프트가 습격해올지 모르는 상황이라고요.","JPN":"リブ卿。集中してください。いつレッドシフトが襲撃してくるかわからない状況なんですよ。","ENG":"Dame Liv, please focus. We don't know when Red Shift might attack.","TWN":"莉芙。請集中注意力。現在是紅移隨時可能襲來的情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그것 말인데, 이렇게 하루 종일 죽치고 있는 게 무슨 의미가 있어?","JPN":"それなんだけど、こうやって一日中待機してるのって何か意味があるの？","ENG":"That's what I'm saying. What's the point of sitting around like this all day?","TWN":"話說，整天待在這裡有什麼意義呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"당장 걔네가 언제 쳐들어올지도 모르잖아.","JPN":"今すぐあいつらが攻撃してくるかもしれないじゃん。","ENG":"It's not like we have any idea when they'll show up.","TWN":"他們隨時可能會進攻，我們也不知道什麼時候會發生。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"작전 브리핑 때 공유 받은 내용이잖아요. 그새 까먹으신 건가요?","JPN":"作戦会議で共有していただいた内容じゃないですか。もう忘れたんですか？","ENG":"This was all covered in the briefing. Did you already forget?","TWN":"這是在作戰簡報時分享的內容。你這麼快就忘了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런 걸 했었나?","JPN":"そんなのやったっけ？","ENG":"We had a briefing?","TWN":"有那樣的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"크흠! 다시 한번 설명해 드릴 테니 이번에는 잘 기억해주세요.","JPN":"コホン！　もう一度説明しますから、今度はちゃんと覚えててくださいね。","ENG":"Ahem! Then let me go over it again. This time, please pay attention.","TWN":"咳咳！我會再解釋一次，這次請記住。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"암암리에 활동하던 레드시프트가 직접적인 움직임을 보인 이유.","JPN":"密かに活動していたレッドシフトが直接動き出した理由。","ENG":"The reason Red Shift finally made a move after all their covert activity.","TWN":"暗中活動的紅移開始直接行動的原因。"},"stage":{"bg":"MS_1203","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다른 이유도 있겠지만, 결정적인 건 관리국이 그들을 주시할 수 없는 상황이기 때문입니다.","JPN":"他にもあるでしょうけど、決定的な理由は管理局が彼らを注視できない状況だからです。","ENG":"There might be other reasons, but the biggest one is that the Administration can't monitor them right now.","TWN":"雖然還有其他原因，但最關鍵的是管理局無法監視他們的情況。"},"stage":{"bg":"MS_1203","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"기사단 본부를 공격한 것도 이와 일맥상통하죠.","JPN":"騎士団の本部を攻撃したのも、これと繋がります。","ENG":"That's also why they attacked the Order's HQ.","TWN":"攻擊騎士團總部也是與此一脈相承的。"},"stage":{"bg":"MS_1203","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"And?","TWN":"所以呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"시간에 쫓기는 건 저들이라는 의미예요. 무구가 목적이라면 빠른 시일 내에 움직일 겁니다.","JPN":"余裕がないのは彼らのほうだってことですよ。武具が目的なら、近いうちに動くはずです。","ENG":"It means they're the ones under pressure of time. If they're after Unique Gear, they'll act soon.","TWN":"這意味著時間緊迫的是他們。如果目標是武具，他們會在短時間內行動。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"저희는 그 점을 이용해 고유무장을 이면세계 내 각 함선에 배치. 아군 전력의 분산으로 적의 공격을 유도하는 대신.","JPN":"私たちはそれを利用して、固有武装を裏世界内の各艦船に配置。味方戦力を分散して敵の攻撃を誘導する代わりに。","ENG":"So we've placed the Unique Gear across multiple ships within the Counterside. That way, our forces are spread out and can lure them into attacking.","TWN":"我們利用這一點，將專屬武裝部署在異界內的各艘艦船上。通過分散我方戰力來引導敵人的攻擊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"각 좌표에 즉각적으로 합류할 수 있도록 차원 도약 좌표를 공유하는 겁니다.","JPN":"各座標にすぐ合流できるように、次元跳躍座標を共有するんです。","ENG":"We've also shared the dimension jump coordinates so we can regroup at any point instantly.","TWN":"共用次元跳躍座標，以便能夠立即加入各個座標。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트 입장에서는 함정이라는 걸 알아도 이번 기회를 놓칠 이유가 없죠.","JPN":"レッドシフトからしたら、罠だってわかっていても、このチャンスを逃す理由がないんですよ。","ENG":"Even if Red Shift knows it's a trap, they won't want to pass up the opportunity.","TWN":"對紅移來說，即使知道是陷阱，也沒有理由錯過這次機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L43_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"왜 그러세요, 리브 경?","JPN":"どうしたんですか、リブ卿？","ENG":"Is something wrong, Dame Liv?","TWN":"怎麼了，莉芙？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 진지하게 설명하는 걸 보니 한솔이 맞구나 싶어서.","JPN":"いや、真面目に説明してるのを見ると、本当にイチロウなんだなーって思って。","ENG":"No, just realizing you're definitely Hansol. Explaining things all seriously.","TWN":"沒什麼，看你這認真解釋的樣子，有點懷疑你是不是楊瀚呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그 왜, 혹시 네크로맨시가 되어버린 건 아닐까 했거든.","JPN":"ほら、もしかしてネクロマンシーになってるんじゃないかって思ったりして。","ENG":"For a second I thought maybe you got hit with necromancy or something.","TWN":"我還在想會不會是變成死靈了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"농담으로라도 그런 말은 하지 마세요. 섬뜩하잖아요.","JPN":"冗談でもそんな話しないでください。怖いですよ。","ENG":"Please don't joke like that. It's creepy.","TWN":"就算是開玩笑也不要說那種話，聽著真嚇人。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런 거 아냐. 본부가 습격받았을 때도 난 아저씨들한테서 별다른 낌새를 못 느꼈잖아?","JPN":"そういうんじゃなくてさ。本部が襲撃された時にも、私はおじさんたちから別に何も感じてなかったでしょ？","ENG":"Nah, I mean it. I didn't pick up on anything weird when HQ got attacked either.","TWN":"不是那樣的。當總部被襲擊時，我也沒有從那些叔叔們那裡察覺到什麼異常吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그러니까… 이번만큼은 조금 정신을 다잡아야겠다 싶었거든.","JPN":"だから……今回だけはちょっとしっかりしないとって思って。","ENG":"So this time... I figured I should probably try to focus.","TWN":"所以……至少這一次，我覺得自己應該稍微振作精神。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그런 분이 브리핑 때는 왜 딴청을 부린 건가요?","JPN":"そういう人が、どうして会議はちゃんと聞いてなかったんですか？","ENG":"If that's true, why were you goofing off during the briefing?","TWN":"那為什麼在簡報時心不在焉呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"전부 기억하고 있어. 방금 말했지만 혹시 모르는 상황을 대비해 확인해봤을 뿐이라고.","JPN":"全部ちゃんと覚えてるよ。さっきも言ったけど、万が一の状況に備えて確認してみただけ。","ENG":"I remembered everything. I was just double-checking in case something changed.","TWN":"我全都記得。正如剛才所說，只是為了以防萬一才確認了一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 왜 그런 눈으로 봐?","JPN":"な、なによ、その目は。","ENG":"What? Why are you looking at me like that?","TWN":"怎麼了，為什麼用那種眼神看我？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"혹시, 네크로맨시?","JPN":"もしかして、ネクロマンシー？","ENG":"You're not the one under necromancy, right?","TWN":"難道是死靈術？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"우쒸! 날 대체 뭐라고 생각하는 거야?","JPN":"ちょっと！　私を何だと思ってるの？","ENG":"Hey! What kind of person do you think I am?!","TWN":"可惡！你到底把我當成什麼人了啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"리브 경, 한솔 경! 북동쪽 방면에서 레드시프트의 움직임이 포착되었습니다!","JPN":"リブ卿、ヤガミ卿！　北東の方面でレッドシフトが動きました！","ENG":"Dame Liv, Sir Hansol! We've detected Red Shift movement to the northeast!","TWN":"莉芙、楊瀚！在東北方向發現了紅移的動向！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"에너지 파형의 분석결과, 본부를 습격했던 여성이 틀림없습니다!","JPN":"エネルギー波形を分析した結果、本部を襲撃した女性です！","ENG":"Analysis shows it's the same woman who attacked HQ!","TWN":"根據能量波形分析，襲擊總部的女性無疑就是她！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"올 게 왔네. 기다리다 지치는 줄 알았어.","JPN":"ついに来たね。待ちくたびれちゃったよ。","ENG":"Finally. I was about to die of boredom waiting.","TWN":"終於來了。我都快等得不耐煩了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"인원수는? 저쪽은 어떤 행동을 취하고 있죠?","JPN":"人数は？　あっちはどう行動してるんですか？","ENG":"How many? What are they doing?","TWN":"人數呢？對方有什麼行動嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그, 그게… 아무 방비 없이 보란 듯 걸어오고 있습니다.","JPN":"そ、それが……無防備状態で、堂々と歩いて来ています。","ENG":"U-uh... she's walking toward us. Boldly. No defenses.","TWN":"那，那個…毫無防備地大搖大擺走過來了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"의외네~? 함선까지 있으니 눈앞에다 폭탄이라도 쏴댈 줄 알았어.","JPN":"意外だね～？　艦船まであるから、爆弾でも撃ってくるのかと思ったよ。","ENG":"Huh? I thought you'd fire a bomb straight at me, with all these ships around.","TWN":"有點意外啊～? 既然有艦船，我還以為會直接在眼前發射炸彈呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"맨몸으로 툭 튀어나오다니, 무슨 자신감?","JPN":"生身で出てくるとか、自信満々だね？","ENG":"But here you are, all exposed. Confident, huh?","TWN":"赤手空拳就這樣冒出來，哪來的自信？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그건 이쪽에서 할 말입니다.","JPN":"それはこっちのセリフです。","ENG":"That's our line.","TWN":"這話該我們說才對。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"대놓고 모습을 보여주다니. 저희가 지원을 부를 거란 생각은 안 하는 건가요?","JPN":"堂々と姿を現すなんて。私たちが支援を呼ぶとは思ってないんですか？","ENG":"You're just strolling in like this? You think we won't call for backup?","TWN":"居然敢公然現身。難道沒想到我們會呼叫支援嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"당연히 했지? 내가 아니라 카란티시르 단장님이!","JPN":"もちろん思ったよ？　アタシじゃなくて、カランティシル団長が！","ENG":"Of course I thought about that. Not me. Our captain, Carantisir, did!","TWN":"當然呼叫了。不是我，是卡蘭堤西爾團長！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데~. 지원이란 건 도착해야 의미 있는 거잖아?","JPN":"でもさ～支援って到着しないと意味ないじゃん？","ENG":"But backup only matters if it actually arrives, right?","TWN":"不過～支援只有到達了才有意義，不是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"천칭이랑 안경 죽도 둘이서, 날 막을 수 있겠어~?","JPN":"天秤と眼鏡竹刀の2人で、アタシを止められるの～？","ENG":"You've only got Libra and bamboo sword with glasses here. Think the two of you can stop me?","TWN":"天秤和眼鏡竹刀兩個人，能阻止我嗎～？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"둘…? 네 눈엔 우리가 둘로 보여?","JPN":"2人……？　あなたの目には私たちが2人に見える？","ENG":"Two of us...? Is that all you see?","TWN":"兩個…? 你覺得我們看起來像兩個人嗎?"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"각오하는 게 좋을 거야.","JPN":"覚悟した方がいいよ。","ENG":"You'd better brace yourself.","TWN":"做好覺悟吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"지난번이랑 달리, 이번엔 신경 쓰면서 싸울 필요가 없거든.","JPN":"この前とは違って、今度は心置きなく戦えるからね。","ENG":"Unlike last time, I don't have to hold back anymore.","TWN":"這次和上次不同，這次不需要費心去戰鬥了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"싸움 이외의 생각을 할 수 있다니. 너 보기보다 똑똑하구나?","JPN":"戦う時に何かを考えることができるなんて。君、思ったより頭いいね？","ENG":"Wow, thinking while fighting? Guess you're smarter than you look.","TWN":"居然能想到打架以外的事情，你比看起來聰明啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"난 바보라서~? 싸움 말고는 몰라!","JPN":"アタシはバカだから～？　戦うこと以外はよくわかんない！","ENG":"I'm dumb, see? Fighting's all I know!","TWN":"因為我是傻瓜～？除了打架什麼都不懂！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"예상대로 지팡이를 사용하는군요.","JPN":"予想どおり、杖を使いますね。","ENG":"As expected. She's using the Staff.","TWN":"果然使用了復活之杖。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮아. 모양새만 그럴듯하지. 클리포트 게임 때 상대했던 침식체들보단 훨씬 약해.","JPN":"大丈夫。それっぽく見えるけど、クリフォトゲームの時に相手してた侵食体よりずっと弱い。","ENG":"Doesn't matter. It looks fancy, but it's way weaker than the C.O.s we fought in the Qliphoth Game.","TWN":"沒關係。只是看起來像那麼回事。比起逆卡巴拉遊戲時遇到的侵蝕體要弱得多。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장 선까지 갈 필요 없이 우리 선에서 끝내자, 한솔!","JPN":"副団長が出るまでもないよ。私たちで終わらせよう、イチロウ！","ENG":"No need to involve Deputy. Let's finish this ourselves, Hansol.","TWN":"不用讓副團長出面，我們自己解決吧，楊瀚！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"네. 부족하지만 최선을 다해 싸우겠습니다!","JPN":"はい。まだまだですけど、頑張って戦います！","ENG":"Yes. I'll give it everything I've got!","TWN":"好的。雖然能力有限，但我會盡力戰鬥！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"전력 좋아! 이게 기사들의 결투라는 거지?","JPN":"全力いいね！　これが騎士たちの決闘ってものかな！","ENG":"Nice! So this is what a real knight's duel feels like?","TWN":"全力以赴！這就是騎士的覺悟吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"경력 상으로는 너네가 선배니까~. 한 수 배울 수 있으면 좋겠다.","JPN":"経験では君たちが先輩だから～何か教えてもらえたらいいね。","ENG":"You two've been at this longer than I have. Hope I can pick up a trick or two!","TWN":"從經驗上來說，你們是前輩呢～。望能向你們學習一招。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니까… 내 이름이……","JPN":"ええっと……アタシの名前は……","ENG":"Oh, right... my name is...","TWN":"我的名字是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그래!","JPN":"あ、そうだ！","ENG":"Ah, yeah!","TWN":"沒錯！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"거해궁의 기사. 아셀라 프로체니카.","JPN":"巨蟹宮の騎士、アセッラ・プロチェニカ。","ENG":"Knight of Cancer, Ascella Procenica.","TWN":"巨蟹座騎士，亞瑟拉·普羅切尼卡。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"갑니다~?","JPN":"行っくよ～？","ENG":"Here I come!","TWN":"要上了～？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};